+      console.log(
+        `│ ${test.name.padEnd(38)} │ ${('ERROR').padStart(9)} │ ${('0%').padStart(12)} │ ${'failed'.padEnd(12)} │`
+      );
+
+      results.push({
+        name: test.name,
+        success: false,
+        confidence: 0,
+        latency: 0,
+        strategy: 'failed',
+        error: error.message,
+      });
