+  console.log('═══════════════════════════════════════════════════════════════════════════════════\n');
+  console.log(`📄 Detailed results: ${outputPath}\n`);
+
+}).catch(err => {
+  console.error('❌ Test failed:', err);
+  process.exit(1);
+});

